public int[] shiftLeft(int[] nums)
{
    int[] shifted = new int[nums.length];

    if (nums.length <= 1)
   	{
       	return nums;
   	}

    else
    {
        shifted[shifted.length - 1] = nums[0];
   		for (int i = 1; i < nums.length; i++)
   		{
       		shifted[i - 1] = nums[i];
   		}
    	return shifted;
    }
}

